        $warnCount++
        continue
    }

    # Get last run result
    try {
        $taskInfo = Get-ScheduledTaskInfo -TaskPath $taskPath -TaskName $taskName -ErrorAction Stop
    } catch { }

    $lastResult = 'unknown'
    $resultVerdict = '[OK]'
    $resultDetail  = ''

    if ($null -ne $taskInfo) {
