        } elseif ($lastResult -eq 2) {
            $resultVerdict = '[!!]'
            $resultDetail  = 'Last result: 0x2 (ERROR_FILE_NOT_FOUND). MpCmdRun.exe may be missing or task XML path is corrupt.'
