                    $warnCount++
                } else {
                    Write-Output "[i]   Volume $mp (WMI)"
                    Write-Output "       Status: $convStr. Protection: $protStr. Method: $encStr."
                }
            }
        } else {
            $wasBLAccessDenied = ($null -ne $blError -and ($blError -like '*Access*denied*' -or $blError -like '*0x80070005*'))
            if ($wasBLAccessDenied) {
                Write-Output '[!!]  BitLocker Status'
                Write-Output '       ACCESS DENIED -- BitLocker queries require Administrator or SYSTEM privileges.'
                Write-Output '       Re-run this script in an elevated PowerShell window or via the RMM tool.'
            } else {
                Write-Output '[!!]  BitLocker Status'
                Write-Output '       Could not query BitLocker volumes.'
                if (-not [string]::IsNullOrWhiteSpace($blError)) {
                    Write-Output "       Get-BitLockerVolume: $blError"
                }
                Write-Output '       WMI Win32_EncryptableVolume returned no data.'
                Write-Output '       Possible causes: BitLocker feature not installed, no encryptable volumes found,'
                Write-Output '       or TPM/hardware prerequisites not met. Run BL002 BLTpmHealth to investigate.'
            }
            $issueCount++
        }
    } catch {
        $wmiErr = $_.Exception.Message
        $isAccessDenied = ($wmiErr -like '*Access*denied*' -or $wmiErr -like '*0x80070005*')
        $wasBLAccessDenied = ($null -ne $blError -and ($blError -like '*Access*denied*' -or $blError -like '*0x80070005*'))
        if ($isAccessDenied -or $wasBLAccessDenied) {
            Write-Output '[!!]  BitLocker Status'
            Write-Output '       ACCESS DENIED -- BitLocker queries require Administrator or SYSTEM privileges.'
            Write-Output '       Re-run this script in an elevated PowerShell window or via the RMM tool.'
            $issueCount++
        } elseif ($wmiErr -like '*Invalid namespace*' -or $wmiErr -like '*not found*') {
            Write-Output '[!!]  BitLocker Status'
            Write-Output '       BitLocker is not available on this Windows edition.'
            Write-Output "       WMI namespace not found: $wmiErr"
            $issueCount++
        } else {
            Write-Output '[!!]  BitLocker Status'
            Write-Output '       Could not query BitLocker volumes.'
            if (-not [string]::IsNullOrWhiteSpace($blError)) {
                Write-Output "       Get-BitLockerVolume: $blError"
            }
            Write-Output "       WMI fallback: $wmiErr"
            Write-Output '       Possible causes: BitLocker feature not installed, no encryptable volumes,'
            Write-Output '       or TPM/hardware prerequisites not met. Run BL002 BLTpmHealth to investigate.'
            $issueCount++
        }
    }
}

if ($null -ne $volumes) {
    $fixedVols = @($volumes | Where-Object { $_.VolumeType -ne 'RemovableData' -and $_.VolumeType -ne $null })
    if ($fixedVols.Count -eq 0) {
        $fixedVols = @($volumes)
    }

    foreach ($vol in $fixedVols) {
        $mp       = $vol.MountPoint
        $vType    = $vol.VolumeType
        $vStatus  = $vol.VolumeStatus
        $pct      = $vol.EncryptionPercentage
        $protStat = $vol.ProtectionStatus
        $encMeth  = $vol.EncryptionMethod
        $lockStat = $vol.LockStatus

        # Build key protector type list
        $kpTypes = @()
        if ($null -ne $vol.KeyProtector) {
            foreach ($kp in $vol.KeyProtector) {
                $kpTypes += $kp.KeyProtectorType.ToString()
            }
        }
        $kpStr = if ($kpTypes.Count -gt 0) { $kpTypes -join ', ' } else { 'None' }

        $hasTpm = $kpTypes -contains 'Tpm' -or $kpTypes -contains 'TpmPin' -or $kpTypes -contains 'TpmStartupKey' -or $kpTypes -contains 'TpmPinStartupKey'
        $hasRecovery = $kpTypes -contains 'RecoveryPassword'

        $detail1 = "Status: $vStatus. Protection: $protStat. Method: $encMeth."
        $detail2 = "Type: $vType. Lock: $lockStat. Protectors: $kpStr."

        if ($vStatus -eq 'FullyEncrypted' -and $protStat -eq 'On') {
            if ($hasTpm -and $hasRecovery) {
                Write-Output "[OK]  Volume $mp"
                Write-Output "       $detail1"
                Write-Output "       $detail2"
            } elseif (-not $hasRecovery) {
                Write-Output "[!]   Volume $mp"
                Write-Output "       $detail1"
                Write-Output "       $detail2"
                Write-Output "       No RecoveryPassword protector found. Key escrow may have failed."
                Write-Output "       Run BL005 BLEscrowCheck to investigate."
                $warnCount++
            } else {
                Write-Output "[OK]  Volume $mp"
                Write-Output "       $detail1"
                Write-Output "       $detail2"
            }
        } elseif ($vStatus -eq 'FullyEncrypted' -and $protStat -eq 'Off') {
            Write-Output "[!!]  Volume $mp"
            Write-Output "       GHOST STATE -- Volume is encrypted but protection is OFF."
            Write-Output "       The encryption key is in the clear. Data is not actually protected."
            Write-Output "       $detail2"
            Write-Output "       Run BL009 BLTpmRemediation to bind a key protector."
            $issueCount++
        } elseif ($vStatus -eq 'FullyDecrypted') {
            Write-Output "[!!]  Volume $mp"
            Write-Output "       Not encrypted. $detail2"
            Write-Output "       Run BL002 BLTpmHealth to check encryption readiness."
            $issueCount++
        } elseif ($vStatus -eq 'EncryptionInProgress') {
            Write-Output "[i]   Volume $mp"
            Write-Output "       Encryption in progress ($pct%). $detail2"
            Write-Output "       This is normal during initial provisioning. Re-run BL001 to check progress."
        } elseif ($vStatus -eq 'EncryptionPaused') {
            Write-Output "[!!]  Volume $mp"
            Write-Output "       Encryption PAUSED at $pct%. Encryption was interrupted and needs intervention."
            Write-Output "       $detail2"
            Write-Output "       Run BL009 BLTpmRemediation to resume or restart."
            $issueCount++
        } elseif ($vStatus -eq 'DecryptionInProgress') {
            Write-Output "[!]   Volume $mp"
            Write-Output "       Decryption in progress ($pct%). Someone or something is actively decrypting."
            Write-Output "       $detail2"
            $warnCount++
        } elseif ($vStatus -eq 'EncryptionSuspended' -or $protStat -eq 'Off') {
            Write-Output "[!]   Volume $mp"
            Write-Output "       Protection suspended. $detail1"
            Write-Output "       $detail2"
            $warnCount++
        } else {
            Write-Output "[i]   Volume $mp"
            Write-Output "       $detail1"
            Write-Output "       $detail2"
        }
    }
}

# --- Check 2: OS Drive Letter Validation ---
$osDrive = $env:SystemDrive
if ($osDrive -eq 'C:') {
    Write-Output '[OK]  OS Drive Letter'
    Write-Output '       OS is on C: as expected. Intune policies will target the correct volume.'
} else {
    Write-Output '[!!]  OS Drive Letter'
    Write-Output "       OS is on $osDrive -- NOT the standard C: drive."
    Write-Output '       Intune BitLocker policies and remediation scripts assume C: and may target the wrong volume.'
    $issueCount++
}

# --- Check 3: Last BitLocker Event ---
$eventIdMap = @{
    768 = 'Encryption started successfully'
    770 = 'Decryption started'
    771 = 'Decryption paused or stopped'
    775 = 'Encryption method and key protector set'
    778 = 'Volume reverted to unprotected state'
    805 = 'Volume unlocked with recovery key (protector failure occurred)'
    810 = 'BitLocker cannot use Secure Boot for integrity validation'
    846 = 'Recovery key escrow to Entra ID FAILED'
    851 = 'Silent encryption FAILED'
    853 = 'TPM not found or bootable media detected'
    854 = 'WinRE not configured -- encryption blocked'
}

$failureIds = @(846, 851, 853, 854)
$warningIds = @(778, 805, 810, 770, 771)

try {
    $lastEvent = Get-WinEvent -LogName 'Microsoft-Windows-BitLocker/BitLocker Management' -MaxEvents 1 -ErrorAction Stop
    if ($null -ne $lastEvent) {
        $evId = $lastEvent.Id
        $evTime = $lastEvent.TimeCreated.ToString('yyyy-MM-dd HH:mm')
        $evMsg = $lastEvent.Message
        if ($null -ne $evMsg -and $evMsg.Length -gt 200) {
            $evMsg = $evMsg.Substring(0, 200) + '...'
        }

        $evSummary = if ($eventIdMap.ContainsKey($evId)) { $eventIdMap[$evId] } else { '' }

        if ($failureIds -contains $evId) {
            Write-Output "[!!]  Last BitLocker Event (ID $evId, $evTime)"
            if ($evSummary -ne '') {
                Write-Output "       $evSummary"
            }
            Write-Output "       $evMsg"
            Write-Output '       Run BL007 BLEventAnalysis for the full failure timeline.'
            $issueCount++
        } elseif ($warningIds -contains $evId) {
            Write-Output "[!]   Last BitLocker Event (ID $evId, $evTime)"
            if ($evSummary -ne '') {
                Write-Output "       $evSummary"
            }
            Write-Output "       $evMsg"
            $warnCount++
        } else {
            Write-Output "[OK]  Last BitLocker Event (ID $evId, $evTime)"
            if ($evSummary -ne '') {
                Write-Output "       $evSummary"
            }
            Write-Output "       $evMsg"
        }
    } else {
        Write-Output '[i]   Last BitLocker Event'
        Write-Output '       No events found. Encryption may never have been attempted on this machine.'
    }
} catch {
    $errMsg = $_.Exception.Message
    if ($errMsg -like '*No events were found*' -or $errMsg -like '*There is not an event log*') {
        Write-Output '[i]   Last BitLocker Event'
        Write-Output '       No BitLocker management events found. Encryption may never have been attempted.'
    } else {
        Write-Output '[i]   Last BitLocker Event'
        Write-Output "       Could not read BitLocker event log: $errMsg"
    }
}

# --- Check 4: BDESVC Service Health ---
$bdesvc = Get-Service -Name 'BDESVC' -ErrorAction SilentlyContinue
if ($null -eq $bdesvc) {
    Write-Output '[!!]  BitLocker Service (BDESVC)'
    Write-Output '       Service not found. BitLocker may not be available on this Windows edition.'
    $issueCount++
} else {
    $bdeStatus = $bdesvc.Status.ToString()
    $bdeStart  = $bdesvc.StartType.ToString()

    if ($bdeStart -eq 'Disabled') {
        Write-Output '[!!]  BitLocker Service (BDESVC)'
        Write-Output '       DISABLED. All BitLocker operations will fail.'
        Write-Output '       Run BL009 BLTpmRemediation or re-enable the service manually.'
        $issueCount++
    } elseif ($bdeStatus -ne 'Running' -and ($bdeStart -eq 'Manual' -or $bdeStart -eq 'Automatic')) {
        Write-Output '[OK]  BitLocker Service (BDESVC)'
        Write-Output "       $bdeStatus, start type: $bdeStart. This is expected -- service starts on demand."
    } else {
        Write-Output '[OK]  BitLocker Service (BDESVC)'
        Write-Output "       $bdeStatus, start type: $bdeStart. Operational."
    }
}

# --- Summary ---
Write-Output ''
$totalProblems = $issueCount + $warnCount
if ($totalProblems -eq 0) {
    Write-Output 'RESULT: No issues detected. BitLocker appears healthy.'
} elseif ($issueCount -gt 0 -and $warnCount -gt 0) {
    Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found. Review items marked [!!] and [!] above."
} elseif ($issueCount -gt 0) {
    Write-Output "RESULT: $issueCount issue(s) found. Review items marked [!!] above."
} else {
    Write-Output "RESULT: $warnCount warning(s) found. Review items marked [!] above."
}
Write-Output ''
Write-Output 'NEXT:   If not encrypted and no errors  -> run BL002 BLTpmHealth to check TPM readiness'
Write-Output '        If encryption failed            -> run BL007 BLEventAnalysis for the failure reason'
Write-Output '        If suspended                    -> run BL009 BLTpmRemediation to resume or restart'
Write-Output '        If encrypted but Intune non-compliant -> force Intune sync (INT001)'
Write-Output '        If ghost state (encrypted, protection off) -> run BL009 BLTpmRemediation'
Write-Output '        If no recovery key              -> run BL005 BLEscrowCheck'

$ErrorActionPreference = 'SilentlyContinue'
Write-Output ''
Write-Output '=== TPM Health & Readiness ==='
Write-Output ''

$issueCount = 0
$warnCount  = 0
$tpmPresent = $false

# ---------------------------------------------------------------
# Check 1: TPM Presence & State
# ---------------------------------------------------------------
Write-Output '--- TPM Presence & State ---'

$tpmObj = $null
$tpmOK = $false
$usedFallback = $false

try {
    $tpmObj = Get-Tpm -ErrorAction Stop
    if ($null -ne $tpmObj) { $tpmOK = $true }
} catch { }

if (-not $tpmOK) {
    # Fallback: tpmtool.exe getdeviceinformation
    $tpmToolPath = Join-Path $env:WinDir 'System32\tpmtool.exe'
    if (Test-Path $tpmToolPath) {
        try {
            $tpmToolOutput = & $tpmToolPath getdeviceinformation 2>&1
            $usedFallback = $true
            if ($null -ne $tpmToolOutput) {
                $tpmToolLines = @($tpmToolOutput | ForEach-Object { $_.ToString().Trim() })
                $fbPresent = $false
                $fbVersion = ''
                $fbVendor  = ''
                $fbLocked  = $false
                $fbInit    = $false
                foreach ($line in $tpmToolLines) {
                    if ($line -match 'TPM Present\s*:\s*(.+)') {
                        $fbPresent = ($Matches[1].Trim() -eq 'True')
                    }
                    if ($line -match 'TPM Version\s*:\s*(.+)') {
                        $fbVersion = $Matches[1].Trim()
                    }
                    if ($line -match 'TPM Manufacturer ID\s*:\s*(.+)') {
                        $fbVendor = $Matches[1].Trim()
                    }
                    if ($line -match 'Is Locked Out\s*:\s*(.+)') {
                        $fbLocked = ($Matches[1].Trim() -eq 'True')
                    }
                    if ($line -match 'Is Initialized\s*:\s*(.+)') {
                        $fbInit = ($Matches[1].Trim() -eq 'True')
                    }
                }
                if ($fbPresent) {
                    $tpmPresent = $true
                    Write-Output '[i]   TPM Present (tpmtool.exe fallback)'
                    Write-Output '       Get-Tpm cmdlet unavailable. Using tpmtool.exe for basic diagnostics.'
                    Write-Output "       TPM Present: True. Version: $fbVersion. Manufacturer: $fbVendor."
                    if ($fbInit) {
                        Write-Output '       Initialized: True.'
                    } else {
                        Write-Output '[!!]  TPM Not Initialized'
                        Write-Output '       The TPM has not been provisioned by the OS.'
                        $issueCount++
                    }
                    if ($fbLocked) {
                        Write-Output '[!!]  TPM Locked Out (tpmtool)'
                        Write-Output '       The TPM is currently refusing authentication commands.'
                        Write-Output '       Wait for the lockout to expire with the system powered on.'
                        $issueCount++
                    }
                } else {
                    Write-Output '[!!]  TPM Not Present'
                    Write-Output '       tpmtool.exe reports no TPM hardware detected.'
                    Write-Output '       Check BIOS/UEFI settings -- TPM may be disabled at the silicon level.'
                    $issueCount++
                }
                # With fallback, we have limited data. Report what we can and skip deep checks.
                Write-Output ''
                Write-Output '[i]   Limited diagnostics available via tpmtool.exe fallback.'
                Write-Output '       For full TPM health analysis, ensure the TrustedPlatformModule PowerShell module'
                Write-Output '       is available. Run: Get-Module -ListAvailable TrustedPlatformModule'
            } else {
                Write-Output '[!!]  TPM Status Unavailable'
                Write-Output '       Get-Tpm cmdlet failed and tpmtool.exe returned no data.'
                Write-Output '       TPM infrastructure may be missing or corrupted.'
                $issueCount++
            }
        } catch {
            Write-Output '[!!]  TPM Status Unavailable'
            Write-Output '       Get-Tpm cmdlet failed and tpmtool.exe also failed.'
            Write-Output '       TPM infrastructure may be missing or corrupted.'
            $issueCount++
        }
    } else {
        Write-Output '[!!]  TPM Status Unavailable'
        Write-Output '       Get-Tpm cmdlet failed. tpmtool.exe not found.'
        Write-Output '       TPM infrastructure may be missing or corrupted.'
        $issueCount++
    }
} else {
    # Get-Tpm succeeded
    $tpmPresent = $tpmObj.TpmPresent

    if (-not $tpmPresent) {
        Write-Output '[!!]  TPM Not Present'
        Write-Output '       TpmPresent: False. No TPM hardware detected by the operating system.'
        Write-Output '       Check BIOS/UEFI settings -- TPM is often disabled by default on new hardware.'
        Write-Output '       BitLocker cannot use seamless pre-boot unlocking without a TPM.'
        $issueCount++
    } else {
        # TPM Present
        Write-Output '[OK]  TPM Present'
        Write-Output '       TpmPresent: True. The operating system detects the TPM hardware.'

        # TpmReady
        if ($tpmObj.TpmReady) {
            Write-Output '[OK]  TPM Ready'
            Write-Output '       TpmReady: True. TPM is fully compliant with Windows standards.'
        } else {
            Write-Output '[!!]  TPM Not Ready'
            Write-Output '       TpmReady: False. The TPM does not meet Windows readiness requirements.'
            Write-Output '       BitLocker and other cryptographic services cannot use this TPM.'
            $issueCount++
        }

        # TpmEnabled & TpmActivated
        $tpmEnabled   = $tpmObj.TpmEnabled
        $tpmActivated = $tpmObj.TpmActivated
        if ($tpmEnabled -and $tpmActivated) {
            Write-Output '[OK]  TPM Enabled & Activated'
            Write-Output '       TpmEnabled: True. TpmActivated: True.'
        } else {
            if (-not $tpmEnabled) {
                Write-Output '[!!]  TPM Not Enabled'
                Write-Output '       TpmEnabled: False. The TPM is present but disabled.'
                Write-Output '       Enable the TPM in BIOS/UEFI settings.'
                $issueCount++
            }
            if (-not $tpmActivated) {
                Write-Output '[!!]  TPM Not Activated'
                Write-Output '       TpmActivated: False. The TPM is enabled but not activated for cryptographic operations.'
                Write-Output '       Activation is typically done via BIOS/UEFI or OS provisioning.'
                $issueCount++
            }
        }

        # TpmOwned
        if ($tpmObj.TpmOwned) {
            Write-Output '[OK]  TPM Ownership'
            Write-Output '       TpmOwned: True. Windows has taken ownership of the TPM.'
        } else {
            Write-Output '[!]   TPM Not Owned'
            Write-Output '       TpmOwned: False. Windows has not taken ownership of the TPM.'
            $apProp = $tpmObj.AutoProvisioning
            if ($null -ne $apProp) {
                $apStr = $apProp.ToString()
                if ($apStr -eq 'Enabled') {
                    Write-Output '       AutoProvisioning is Enabled. Windows should take ownership on next boot.'
                } else {
                    Write-Output "       AutoProvisioning: $apStr. OS is not permitted to provision the TPM."
                    Write-Output '       Check Group Policy or MDM settings for TPM provisioning restrictions.'
                }
            } else {
                Write-Output '       Unable to determine AutoProvisioning state.'
            }
            $warnCount++
        }
    }
}

Write-Output ''

# Early exit: if TPM is not present AND we used Get-Tpm (not fallback), skip deep checks
if (-not $tpmPresent) {
    Write-Output ''
    if ($issueCount -eq 0 -and $warnCount -eq 0) {
        Write-Output 'RESULT: No issues detected. TPM is healthy and ready for BitLocker.'
    } elseif ($issueCount -eq 0) {
        Write-Output "RESULT: $warnCount warning(s) found. TPM is functional but review the flagged items."
    } else {
        Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found. TPM needs attention."
    }
    Write-Output ''
    Write-Output 'NEXT:   If TPM not present         -> check BIOS settings (often disabled by default)'
    Write-Output '        If TPM 1.2                 -> may need hardware upgrade or BIOS setting to enable 2.0 mode'
    Write-Output '        If firmware flagged        -> visit OEM support site for TPM firmware update'
    Write-Output '        If TPM locked out          -> wait for lockout to expire, then retry'
    Write-Output '        If TPM ready               -> run BL003 BLHardwarePrereqs to check other prerequisites'
    return
}

# If we used the fallback, we also skip deep checks (already reported limited info)
if ($usedFallback) {
    Write-Output ''
    if ($issueCount -eq 0 -and $warnCount -eq 0) {
        Write-Output 'RESULT: No issues detected (limited diagnostics via tpmtool.exe).'
    } elseif ($issueCount -eq 0) {
        Write-Output "RESULT: $warnCount warning(s) found (limited diagnostics via tpmtool.exe)."
    } else {
        Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found (limited diagnostics)."
    }
    Write-Output ''
    Write-Output 'NEXT:   If TPM not present         -> check BIOS settings (often disabled by default)'
    Write-Output '        If TPM 1.2                 -> may need hardware upgrade or BIOS setting to enable 2.0 mode'
    Write-Output '        If firmware flagged        -> visit OEM support site for TPM firmware update'
    Write-Output '        If TPM locked out          -> wait for lockout to expire, then retry'
    Write-Output '        If TPM ready               -> run BL003 BLHardwarePrereqs to check other prerequisites'
    return
}

# ---------------------------------------------------------------
# Check 2: TPM Version
# ---------------------------------------------------------------
Write-Output '--- TPM Version ---'

$tpmVersion = ''
$tpmPpiVer  = ''

try {
    $wmiTpm = Get-CimInstance -Namespace 'ROOT\CIMv2\Security\MicrosoftTpm' -ClassName Win32_Tpm -ErrorAction Stop
    if ($null -ne $wmiTpm) {
        $specVer = $wmiTpm.SpecVersion
        if (-not [string]::IsNullOrWhiteSpace($specVer)) {
            $specParts = $specVer -split ','
            $tpmVersion = $specParts[0].Trim()

            if ($tpmVersion -eq '2.0') {
                Write-Output '[OK]  TPM Specification Version'
                Write-Output "       Version: 2.0 (SpecVersion: $specVer). Meets modern Intune requirements."
            } elseif ($tpmVersion -eq '1.2') {
                Write-Output '[!]   TPM Specification Version'
                Write-Output "       Version: 1.2 (SpecVersion: $specVer)."
                Write-Output '       Intune compliance policies often require TPM 2.0.'
                Write-Output '       TPM 1.2 limits BitLocker to legacy modes and prevents silent encryption.'
                Write-Output '       Check if BIOS offers a 1.2-to-2.0 firmware switch (some hardware supports this).'
                $warnCount++
            } else {
                Write-Output '[i]   TPM Specification Version'
                Write-Output "       Version: $tpmVersion (SpecVersion: $specVer). Unexpected version."
            }
        } else {
            Write-Output '[i]   TPM Specification Version'
            Write-Output '       SpecVersion property is empty. Unable to determine TPM version from WMI.'
        }

        # PPI version
        $ppiVer = $wmiTpm.PhysicalPresenceVersionInfo
        if (-not [string]::IsNullOrWhiteSpace($ppiVer)) {
            $tpmPpiVer = $ppiVer
            Write-Output "[i]   Physical Presence Interface: $ppiVer"
        }
    } else {
        Write-Output '[i]   TPM Version'
        Write-Output '       Win32_Tpm WMI class returned no data. Unable to determine TPM version.'
    }
} catch {
    $verErr = $_.Exception.Message
    Write-Output '[i]   TPM Version'
    Write-Output "       Could not query Win32_Tpm WMI class: $verErr"
    Write-Output '       TPM version check unavailable.'
}

Write-Output ''

# ---------------------------------------------------------------
# Check 3: Manufacturer & Firmware Vulnerability Check
# ---------------------------------------------------------------
Write-Output '--- TPM Manufacturer & Firmware ---'

$mfgId  = ''
$mfgVer = ''
$mfgVerFull = ''

if ($null -ne $tpmObj) {
    $mfgId  = $tpmObj.ManufacturerIdTxt
    $mfgVer = $tpmObj.ManufacturerVersion
    try {
        $mfgVerFull = $tpmObj.ManufacturerVersionFull20
    } catch { }
}

if ([string]::IsNullOrWhiteSpace($mfgId)) {
    Write-Output '[i]   TPM Manufacturer'
    Write-Output '       ManufacturerIdTxt is empty. Unable to identify TPM vendor.'
    Write-Output '       Firmware vulnerability check skipped.'
} else {
    $vulnFound = $false
    $verForCheck = if (-not [string]::IsNullOrWhiteSpace($mfgVerFull)) { $mfgVerFull } else { $mfgVer }

    # --- Infineon ROCA (CVE-2017-15361) ---
    if ($mfgId -eq 'IFX') {
        # Parse version to check against vulnerable ranges
        # Affected: TPM 1.2 fw < 4.34 or < 6.43; TPM 2.0 fw < 7.63
        # We extract the major.minor from the version string
        $verParts = @()
        if (-not [string]::IsNullOrWhiteSpace($verForCheck)) {
            $verParts = $verForCheck -split '\.'
        }
        $verMajor = 0
        $verMinor = 0
        if ($verParts.Count -ge 1) {
            try { $verMajor = [int]$verParts[0] } catch { }
        }
        if ($verParts.Count -ge 2) {
            try { $verMinor = [int]$verParts[1] } catch { }
        }

        $isVulnerable = $false
        if ($tpmVersion -eq '1.2') {
            # TPM 1.2: vulnerable if major < 4, or (major 4, minor < 34), or (major 6, minor < 43)
            if ($verMajor -lt 4) { $isVulnerable = $true }
            elseif ($verMajor -eq 4 -and $verMinor -lt 34) { $isVulnerable = $true }
            elseif ($verMajor -eq 6 -and $verMinor -lt 43) { $isVulnerable = $true }
        } elseif ($tpmVersion -eq '2.0') {
            # TPM 2.0: vulnerable if major < 7, or (major 7, minor < 63)
            if ($verMajor -lt 7) { $isVulnerable = $true }
            elseif ($verMajor -eq 7 -and $verMinor -lt 63) { $isVulnerable = $true }
        }

        if ($isVulnerable) {
            $vulnFound = $true
            Write-Output '[!!]  Infineon TPM -- CVE-2017-15361 (ROCA Vulnerability)'
            Write-Output "       Manufacturer: $mfgId (Infineon). Firmware: $verForCheck."
            Write-Output '       This firmware has a known RSA key generation flaw. Private keys can be'
            Write-Output '       deduced from public keys via computational attack.'
            Write-Output '       BitLocker keys generated on this firmware may be compromised.'
            Write-Output '       ACTION: Visit OEM support site for a TPM firmware update immediately.'
            $issueCount++
        }
    }

    # --- STMicro TPM-FAIL (CVE-2019-16863) ---
    if ($mfgId -eq 'STM') {
        $verParts = @()
        if (-not [string]::IsNullOrWhiteSpace($verForCheck)) {
            $verParts = $verForCheck -split '\.'
        }
        $verMajor = 0
        $verMinor = 0
        if ($verParts.Count -ge 1) {
            try { $verMajor = [int]$verParts[0] } catch { }
        }
        if ($verParts.Count -ge 2) {
            try { $verMinor = [int]$verParts[1] } catch { }
        }

        $isVulnerable = $false
        # Vulnerable branches: 71.x (safe >= 71.16), 73.x (safe >= 73.20), 74.x (safe >= 74.20)
        if ($verMajor -eq 71 -and $verMinor -lt 16) { $isVulnerable = $true }
        elseif ($verMajor -eq 73 -and $verMinor -lt 20) { $isVulnerable = $true }
        elseif ($verMajor -eq 74 -and $verMinor -lt 20) { $isVulnerable = $true }

        if ($isVulnerable) {
            $vulnFound = $true
            Write-Output '[!!]  STMicro TPM -- CVE-2019-16863 (TPM-FAIL Vulnerability)'
            Write-Output "       Manufacturer: $mfgId (STMicroelectronics). Firmware: $verForCheck."
            Write-Output '       This firmware has an ECDSA side-channel timing attack vulnerability.'
            Write-Output '       Attackers can extract the ECDSA private key via side-channel analysis.'
            Write-Output '       ACTION: Visit OEM support site for a TPM firmware update immediately.'
            $issueCount++
        }
    }

    if (-not $vulnFound) {
        Write-Output "[i]   Manufacturer: $mfgId. Firmware: $verForCheck."
        Write-Output '       No known firmware vulnerabilities for this manufacturer/version combination.'
    }
}

Write-Output ''

# ---------------------------------------------------------------
# Check 4: Lockout State
# ---------------------------------------------------------------
Write-Output '--- Lockout State ---'

if ($null -ne $tpmObj) {
    $lockedOut    = $tpmObj.LockedOut
    $lockCount    = $tpmObj.LockoutCount
    $lockMax      = $tpmObj.LockoutMax
    $lockHealTime = $tpmObj.LockoutHealTime

    if ($lockedOut) {
        Write-Output '[!!]  TPM LOCKED OUT'
        Write-Output '       The TPM is currently refusing all authentication commands.'
        Write-Output "       LockoutCount: $lockCount of $lockMax max attempts."
        if ($null -ne $lockHealTime) {
            $healStr = $lockHealTime.ToString()
            if ($null -ne $lockCount -and $lockCount -gt 0) {
                # Calculate estimated heal duration
                # LockoutHealTime is a TimeSpan - time for count to decrement by 1
                try {
                    $totalHeal = [TimeSpan]::FromTicks($lockHealTime.Ticks * $lockCount)
                    $healHours = [Math]::Round($totalHeal.TotalHours, 1)
                    Write-Output "       Heal time per decrement: $healStr."
                    Write-Output "       Estimated total heal: $healHours hours of CONTINUOUS powered-on time."
                } catch {
                    Write-Output "       LockoutHealTime: $healStr."
                }
            } else {
                Write-Output "       LockoutHealTime: $healStr."
            }
        }
        Write-Output '       The heal timer requires continuous powered-on operation.'
        Write-Output '       Shutdowns, hibernation, and deep sleep pause the timer.'
        Write-Output '       No exact unlock time can be predicted.'
        Write-Output '       No native method exists to clear the lockout without the owner auth password'
        Write-Output '       (which modern Windows discards after provisioning).'
        $issueCount++
    } elseif ($null -ne $lockCount -and $lockCount -gt 0) {
        Write-Output '[!]   TPM Lockout Activity'
        Write-Output "       LockoutCount: $lockCount of $lockMax max. Not locked out, but failed attempts recorded."
        Write-Output '       Investigate what is causing repeated auth failures (PIN brute-force, malware, driver bug).'
        $warnCount++
    } else {
        $maxStr = if ($null -ne $lockMax) { $lockMax.ToString() } else { 'unknown' }
        Write-Output '[OK]  TPM Lockout'
        Write-Output "       Not locked out. LockoutCount: 0 of $maxStr max. No dictionary attack activity."
    }
} else {
    Write-Output '[i]   Lockout State'
    Write-Output '       Get-Tpm data unavailable. Unable to check lockout state.'
}

Write-Output ''

# ---------------------------------------------------------------
# Check 5: Attestation & Provisioning Readiness
# ---------------------------------------------------------------
Write-Output '--- Attestation & Provisioning ---'

# 5a: TBS (TPM Base Services) service
$tbsSvc = $null
try {
    $tbsSvc = Get-Service -Name 'TBS' -ErrorAction Stop
} catch { }

if ($null -eq $tbsSvc) {
    if ($tpmOK) {
        # Get-Tpm succeeded, so TPM operations work despite missing service.
        # Common on virtual machines (e.g., VMware vTPM).
        Write-Output '[i]   TPM Base Services (TBS)'
        Write-Output '       TBS service not found, but TPM operations succeeded.'
        Write-Output '       This is expected on virtual machines with a virtual TPM (e.g., VMware, Hyper-V).'
    } else {
        Write-Output '[!!]  TPM Base Services (TBS)'
        Write-Output '       TBS service not found. TPM driver stack may be missing.'
        Write-Output '       All user-mode TPM access is impossible without this service.'
        $issueCount++
    }
} else {
    $tbsStatus = $tbsSvc.Status
    $tbsStart  = $tbsSvc.StartType
    if ($tbsStatus -eq 'Running') {
        Write-Output '[OK]  TPM Base Services (TBS)'
        Write-Output '       Service is running. TPM stack is operational.'
    } elseif ($tbsStart -eq 'Disabled') {
        Write-Output '[!!]  TPM Base Services (TBS)'
        Write-Output '       Service is DISABLED. No user-mode TPM access possible.'
        Write-Output '       Re-enable the TBS service and restart the machine.'
        $issueCount++
    } else {
        Write-Output '[!!]  TPM Base Services (TBS)'
        Write-Output "       Service status: $tbsStatus (StartType: $tbsStart)."
        Write-Output '       TBS must be running for TPM operations. Start the service or investigate why it stopped.'
        $issueCount++
    }
}

# 5b: Auto-Provisioning (already partially covered in Check 1 for TpmOwned=false)
if ($null -ne $tpmObj -and -not $tpmObj.TpmOwned) {
    # Already reported in Check 1
    Write-Output '[i]   Auto-Provisioning'
    Write-Output '       See TPM Ownership check above for auto-provisioning details.'
} elseif ($null -ne $tpmObj -and $tpmObj.TpmOwned) {
    Write-Output '[OK]  Auto-Provisioning'
    Write-Output '       TPM is owned. Provisioning was successful.'
}

# 5c: Owner Auth Retention level
$tpmPolPath = 'HKLM:\SOFTWARE\Policies\Microsoft\TPM'
$osManagedAuthLevel = $null
try {
    $tpmPolReg = Get-ItemProperty -Path $tpmPolPath -ErrorAction Stop
    if ($null -ne $tpmPolReg) {
        $osManagedAuthLevel = $tpmPolReg.OSManagedAuthLevel
    }
} catch { }

if ($null -ne $osManagedAuthLevel) {
    $authDesc = switch ([int]$osManagedAuthLevel) {
        0 { 'None -- OS stores no owner authorization data. No programmatic TPM clear/reset possible.' }
        2 { 'Delegated -- OS stores admin and user delegation blobs only. Partial programmatic control.' }
        4 { 'Full -- OS retains the full TPM owner authorization password. Full programmatic TPM management available.' }
        5 { 'Default (modern) -- Retains lockout auth, discards full owner. Cannot clear TPM programmatically.' }
        default { "Unknown value: $osManagedAuthLevel" }
    }
    Write-Output '[i]   Owner Auth Retention'
    Write-Output "       OSManagedAuthLevel: $osManagedAuthLevel. $authDesc"
    if ([int]$osManagedAuthLevel -ne 4) {
        Write-Output '       A TPM clear requires physical presence (reboot + BIOS key press).'
    }
} else {
    Write-Output '[i]   Owner Auth Retention'
    Write-Output '       OSManagedAuthLevel not configured by policy. Modern Windows default applies.'
    Write-Output '       Retains lockout auth, discards full owner auth after provisioning.'
    Write-Output '       A TPM clear requires physical presence (reboot + BIOS key press).'
}

Write-Output ''

# ---------------------------------------------------------------
# Summary
# ---------------------------------------------------------------
if ($issueCount -eq 0 -and $warnCount -eq 0) {
    Write-Output 'RESULT: No issues detected. TPM is healthy and ready for BitLocker.'
} elseif ($issueCount -eq 0) {
    Write-Output "RESULT: $warnCount warning(s) found. TPM is functional but review the flagged items."
} else {
    Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found. TPM needs attention."
}

Write-Output ''
Write-Output 'NEXT:   If TPM not present         -> check BIOS settings (often disabled by default)'
Write-Output '        If TPM 1.2                 -> may need hardware upgrade or BIOS setting to enable 2.0 mode'
Write-Output '        If firmware flagged        -> visit OEM support site for TPM firmware update'
Write-Output '        If TPM locked out          -> wait for lockout to expire, then retry'
Write-Output '        If TPM ready               -> run BL003 BLHardwarePrereqs to check other prerequisites'

$ErrorActionPreference = 'SilentlyContinue'
Write-Output ''
Write-Output '=== Firewall Status Triage ==='
Write-Output ''

$issueCount = 0
$warnCount = 0

# State tracking for cross-reference (Check 2)
$anyProfileDisabled = $false
$allProfilesEnabled = $true
$profileStates = @{}

# --- Check 1: Firewall Profile Status ---
# Get active network connections for correlation
$connections = @()
try {
    $connections = @(Get-NetConnectionProfile -ErrorAction Stop)
} catch { }

# Build a lookup: which profiles have active adapters
$activeProfileAdapters = @{}
$activeProfileAdapters['Domain'] = [System.Collections.Generic.List[string]]::new()
$activeProfileAdapters['Private'] = [System.Collections.Generic.List[string]]::new()
$activeProfileAdapters['Public'] = [System.Collections.Generic.List[string]]::new()

foreach ($conn in $connections) {
    $cat = $conn.NetworkCategory.ToString()
    $alias = $conn.InterfaceAlias
    if ($cat -eq 'DomainAuthenticated') {
        $null = $activeProfileAdapters['Domain'].Add($alias)
    } elseif ($cat -eq 'Private') {
        $null = $activeProfileAdapters['Private'].Add($alias)
    } elseif ($cat -eq 'Public') {
        $null = $activeProfileAdapters['Public'].Add($alias)
    }
}

try {
    $profiles = @(Get-NetFirewallProfile -ErrorAction Stop)
    foreach ($p in $profiles) {
        $pName = $p.Name
        $enabled = $p.Enabled
        $inAction = $p.DefaultInboundAction.ToString()
        $outAction = $p.DefaultOutboundAction.ToString()

        $profileStates[$pName] = $enabled

        if (-not $enabled) {
            $anyProfileDisabled = $true
            $allProfilesEnabled = $false
        }

        $adapters = $activeProfileAdapters[$pName]
        $hasAdapters = ($null -ne $adapters -and $adapters.Count -gt 0)
        $adapterStr = if ($hasAdapters) { $adapters -join ', ' } else { 'None' }

        if ($enabled -and $hasAdapters) {
            Write-Output "[OK]  $pName Profile"
            Write-Output "       Enabled. Active on: $adapterStr."
        } elseif ($enabled -and -not $hasAdapters) {
            Write-Output "[OK]  $pName Profile"
            Write-Output "       Enabled. No adapters currently using this profile."
        } elseif (-not $enabled -and $hasAdapters) {
            Write-Output "[!!]  $pName Profile"
            Write-Output "       DISABLED -- but adapter(s) are connected: $adapterStr."
            Write-Output "       Traffic on these adapters is UNFILTERED."
            Write-Output "       Run FW002 FWPolicyConflict to find what disabled it."
            $issueCount++
        } else {
            # Disabled, no active adapters
            Write-Output "[!]   $pName Profile"
            Write-Output "       Disabled. No adapters currently using this profile."
            Write-Output "       Risk: if an adapter connects to a $pName network, traffic will be unfiltered."
            $warnCount++
        }

        # Flag non-standard default actions (only deviations)
        if ($inAction -eq 'Allow') {
            Write-Output "[!]   $pName Profile -- Inbound Default Action"
            Write-Output "       DefaultInboundAction is ALLOW. All inbound traffic is permitted unless explicitly blocked."
            Write-Output "       The expected setting is Block. This is a significant security risk."
            $warnCount++
        }
        if ($outAction -eq 'Block') {
            Write-Output "[i]   $pName Profile -- Outbound Default Action"
            Write-Output "       DefaultOutboundAction is BLOCK. All outbound traffic is denied unless explicitly allowed."
            Write-Output "       This is a restrictive configuration. Expected default is Allow."
        }
    }
} catch {
    Write-Output '[!!]  Firewall Profiles'
    Write-Output "       Could not query firewall profiles: $($_.Exception.Message)"
    Write-Output '       The NetSecurity module may not be available.'
    $issueCount++
}

# --- Check 2: Security Center Cross-Reference ---
$secCenterFirewallOn = $false
$hasThirdPartyFW = $false

try {
    $fwProducts = @(Get-CimInstance -Namespace root/SecurityCenter2 -ClassName FirewallProduct -ErrorAction Stop)
    if ($null -eq $fwProducts -or $fwProducts.Count -eq 0) {
        Write-Output '[i]   Security Center Firewall Products'
        Write-Output '       No firewall products registered in Security Center.'
        Write-Output '       Intune may report firewall as non-compliant due to missing registration.'
    } else {
        $nativeGuid = '{D68DDC3A-831F-4fae-9E44-DA132C1ACF46}'

        foreach ($fw in $fwProducts) {
            $pState = [UInt32]$fw.productState
            $engineBits = $pState -band 0xF000

            $engineState = switch ($engineBits) {
                0x1000 { 'On' }
                0x0000 { 'Off' }
                0x2000 { 'Snoozed' }
                0x3000 { 'Expired' }
                default { "Unknown (0x$($engineBits.ToString('X4')))" }
            }

            $isNative = ($fw.instanceGuid -eq $nativeGuid)

            if ($isNative) {
                if ($engineState -eq 'On') {
                    $secCenterFirewallOn = $true
                    Write-Output "[OK]  Security Center: $($fw.displayName)"
                    Write-Output "       State: $engineState. Native Windows Firewall registered and active."
                } else {
                    Write-Output "[!!]  Security Center: $($fw.displayName)"
                    Write-Output "       State: $engineState. Native Windows Firewall registered but reporting as $engineState."
                    Write-Output "       Intune will see the firewall as non-compliant."
                    $issueCount++
                }
            } else {
                $hasThirdPartyFW = $true
                # Ghost detection: check if executable exists
                $isGhost = $false
                $exePath = $fw.pathToSignedReportingExe
                if (-not [string]::IsNullOrWhiteSpace($exePath)) {
                    if ($exePath -notlike 'windowsdefender://*' -and $exePath -notlike '%*') {
                        if (-not (Test-Path $exePath)) {
                            $isGhost = $true
                        }
                    }
                }

                if ($isGhost) {
                    Write-Output "[!!]  Security Center: $($fw.displayName)"
                    Write-Output "       GHOST REGISTRATION -- product registered but executable not found on disk."
                    Write-Output "       Path: $exePath"
                    Write-Output "       Intune reads this stale entry and may report firewall non-compliant."
                    Write-Output "       Run FW003 FWThirdParty to investigate and FW006 FWRemediation to clean up."
                    $issueCount++
                } elseif ($engineState -eq 'On') {
                    $secCenterFirewallOn = $true
                    Write-Output "[i]   Security Center: $($fw.displayName)"
                    Write-Output "       State: $engineState. Third-party firewall is active."
                    Write-Output "       Windows Firewall may be correctly deferred to this product."
                } else {
                    Write-Output "[!!]  Security Center: $($fw.displayName)"
                    Write-Output "       State: $engineState. Third-party firewall registered but not active."
                    Write-Output "       If this product was uninstalled, this is a ghost registration."
                    Write-Output "       Run FW003 FWThirdParty to investigate."
                    $issueCount++
                }
            }
        }

        # Multiple products warning
        if ($fwProducts.Count -gt 1) {
            Write-Output "[!]   Security Center Product Count"
            Write-Output "       $($fwProducts.Count) firewall products registered. Ghost registration is probable."
            Write-Output "       Run FW003 FWThirdParty for detailed analysis."
            $warnCount++
        }

        # Cross-reference: Security Center vs profile ground truth
        if ($secCenterFirewallOn -and $anyProfileDisabled) {
            Write-Output '[!!]  Security Center vs Profile Desync'
            Write-Output '       Security Center reports firewall ON, but one or more profiles are DISABLED.'
            Write-Output '       Intune sees the firewall as compliant, but traffic may be unfiltered.'
            Write-Output '       This is a false sense of security.'
            $issueCount++
        } elseif (-not $secCenterFirewallOn -and $allProfilesEnabled -and -not $hasThirdPartyFW) {
            Write-Output '[!!]  Security Center vs Profile Desync'
            Write-Output '       All firewall profiles are ENABLED, but Security Center reports firewall OFF.'
            Write-Output '       Intune will incorrectly flag this machine as non-compliant.'
            Write-Output '       Run FW003 FWThirdParty to check for ghost registrations.'
            $issueCount++
        }
    }
} catch {
    $errMsg = $_.Exception.Message
    if ($errMsg -like '*Invalid namespace*' -or $errMsg -like '*not found*') {
        Write-Output '[i]   Security Center Firewall Products'
        Write-Output '       SecurityCenter2 namespace not available (normal on Windows Server).'
        Write-Output '       Skipping Security Center cross-reference.'
    } else {
        Write-Output '[i]   Security Center Firewall Products'
        Write-Output "       Could not query Security Center: $errMsg"
    }
}

# --- Check 3: MpsSvc Service Health ---
$mpssvc = Get-Service -Name 'MpsSvc' -ErrorAction SilentlyContinue
if ($null -eq $mpssvc) {
    Write-Output '[!!]  Firewall Service (MpsSvc)'
    Write-Output '       Service not found. This is a critical system component that should always exist.'
    $issueCount++
} else {
    $mpsStatus = $mpssvc.Status.ToString()
    $mpsStart  = $mpssvc.StartType.ToString()

    if ($mpsStatus -eq 'Running' -and $mpsStart -eq 'Automatic') {
